%[text] # 例6.5（区分的定数関数とDCT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_05"; % mfilename

%imgname = "msipimg01";
%imgname = "msipimg07";
%imgfmt = "tiff";

close all
iFig = 1;
%%
%[text] ## パラメータ設定
K = 4;
M = 2*K;
%Delta = 2/M;
Delta = 1/M;
R = [0 1]; % サポート領域
%%
%[text] ## $\\varphi(\\cdot)$ のプロット
%phi = @(x) fcn_phin(x,0,K,0,0);
phi = @(x) fcn_chi(x,R);

figure(iFig) %[output:2f72daed]
fplot(@(x) phi(x),R) %[output:2f72daed]
axis([-0.1 1.1 -3 3]) %[output:2f72daed]
ylabel('$\varphi(q)$','Interpreter','latex') %[output:2f72daed]
xlabel('$q$','Interpreter','latex') %[output:2f72daed]

grid on %[output:2f72daed]

iFig = iFig + 1;
%%
%[text] ## $\\varphi\_n(\\cdot)$ の構成
xmin = -1;
theta0 = 1/(2*K);

phin = cell(M,1);

for n=0:M-1
    %phin{n+1} = @(x) fcn_phin(x,n,K,xmin,theta0);
    phin{n+1} = @(x) fcn_chi((x-Delta*n)/Delta,R)/sqrt(Delta);
end
%%
%[text] ## $\\varphi\_n(\\cdot)$ のプロット
hfig = figure(iFig); %[output:26a26cd2]

for n=0:M-1
    subplot(M,1,n+1) %[output:26a26cd2]
    fplot(@(x) phin{n+1}(x),R,'k','LineWidth',2)
    axis([-0.1 1.1 -3 3])
    ylabel("$\varphi_"+num2str(n)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if n==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end
figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:26a26cd2]

exportgraphics(hfig,fullfile(resfolder,"fig06-03a.png")) %[output:26a26cd2]

iFig = iFig + 1;
%%
%[text] ## $\\psi\_m(\\cdot)$  の構成
psim = cell(M,1);
C = dctmtx(M);
D = C.';

for m=0:M-1
    psim{m+1} = @(x) 0;
    for n=0:M-1
        dnm = D(n+1,m+1);
        %psim{m+1} = @(x) psim{m+1}(x) + dnm*fcn_phin(x,n,K,xmin,theta0);
        psim{m+1} = @(x) psim{m+1}(x) + dnm*fcn_chi((x-Delta*n)/Delta,R);
    end
end
%%
%[text] ## $\\psi\_m(\\cdot)$のプロット
hfig = figure(iFig); %[output:48c50363]

for m=0:M-1
    subplot(M,1,m+1) %[output:48c50363]
    fplot(@(x) psim{m+1}(x),R,'k','LineWidth',2)
    axis([-0.1 1.1 -3 3])
    ylabel("$\psi_"+num2str(m)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if m==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end
figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:48c50363]

exportgraphics(hfig,fullfile(resfolder,"fig06-03b.png")) %[output:48c50363]
iFig = iFig + 1;
%%
%[text] ## 補間核の定義
function z = fcn_chi(x,y)
arguments (Input)
    x
    y
end

arguments (Output)
    z
end

z = (x>=y(1)).*(x<y(2));
end
